import React, { useEffect, useMemo, useState } from 'react';
import { useParams } from 'react-router-dom';
import { expertAPI, bookingsAPI } from '../services/api';

const DEFAULT_PASSWORD = '123';

const ExpertBookings = () => {
  const { expertId: routeExpertId } = useParams();

  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  const [bookings, setBookings] = useState([]);
  const [confirmingId, setConfirmingId] = useState(null);

  // Expert login (expertId + name + default password)
  const [loginName, setLoginName] = useState('');
  const [loginExpertId, setLoginExpertId] = useState(routeExpertId || '');
  const [loginPassword, setLoginPassword] = useState(DEFAULT_PASSWORD);
  const [loggedIn, setLoggedIn] = useState(false);

  useEffect(() => {
    if (routeExpertId) setLoginExpertId(routeExpertId);
  }, [routeExpertId]);

  const pendingBookings = useMemo(
    () => bookings.filter((b) => b?.status === 'pending' && String(b?.expertId?._id || b?.expertId) === String(routeExpertId)),
    [bookings, routeExpertId]
  );

  const handleLogin = async (e) => {
    e.preventDefault();
    setError(null);

    if (!loginExpertId.trim() || !loginName.trim() || !loginPassword.trim()) {
      setError('Please enter expert ID, expert name, and password.');
      return;
    }

    setLoading(true);
    try {
      const res = await expertAPI.login({
        expertId: loginExpertId.trim(),
        name: loginName.trim(),
        password: loginPassword.trim(),
      });

      setLoggedIn(true);

      // Optional: persist for convenience
      localStorage.setItem(
        'expertLogin',
        JSON.stringify({
          expertId: res.data?.expert?._id || loginExpertId.trim(),
          name: res.data?.expert?.name || loginName.trim(),
          loggedInAt: Date.now(),
        })
      );

      // Load pending bookings for this expertId
      const bookingsRes = await bookingsAPI.getBookingsByExpertId(loginExpertId.trim());
      setBookings(bookingsRes.data.bookings || []);
    } catch (err) {
      setLoggedIn(false);
      setBookings([]);
      setError(err.response?.data?.message || 'Failed to login');
    } finally {
      setLoading(false);
    }
  };

  const handleConfirm = async (bookingId) => {
    setConfirmingId(bookingId);
    setError(null);

    try {
      await bookingsAPI.updateBookingStatus(bookingId, { status: 'confirmed' });

      // Optimistic UI update
      setBookings((prev) => prev.map((b) => (b._id === bookingId ? { ...b, status: 'confirmed' } : b)));
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to confirm booking');
    } finally {
      setConfirmingId(null);
    }
  };

  return (
    <div className="space-y-8">
      <div className="text-center">
        <h1 className="text-4xl font-bold text-white">Expert Dashboard</h1>
        <p className="text-slate-400 mt-2">Login and confirm pending bookings for your sessions</p>
      </div>

      <div className="bg-slate-800 rounded-lg border border-slate-700 p-8">
        <form onSubmit={handleLogin} className="flex gap-4 flex-col sm:flex-row">
          <input
            type="text"
            placeholder="Expert MongoDB ID"
            value={loginExpertId}
            onChange={(e) => setLoginExpertId(e.target.value)}
            className="flex-1 px-4 py-2 bg-slate-900 border border-slate-700 rounded-lg text-white placeholder-slate-500 focus:outline-none focus:border-blue-500 focus:ring-1 focus:ring-blue-500 transition-all duration-200"
          />
          <input
            type="text"
            placeholder="Expert Name"
            value={loginName}
            onChange={(e) => setLoginName(e.target.value)}
            className="flex-1 px-4 py-2 bg-slate-900 border border-slate-700 rounded-lg text-white placeholder-slate-500 focus:outline-none focus:border-blue-500 focus:ring-1 focus:ring-blue-500 transition-all duration-200"
          />
          <input
            type="password"
            placeholder="Password (default 123)"
            value={loginPassword}
            onChange={(e) => setLoginPassword(e.target.value)}
            className="flex-1 px-4 py-2 bg-slate-900 border border-slate-700 rounded-lg text-white placeholder-slate-500 focus:outline-none focus:border-blue-500 focus:ring-1 focus:ring-blue-500 transition-all duration-200"
          />
          <button
            type="submit"
            disabled={loading}
            className="px-6 py-2 bg-gradient-to-r from-blue-500 to-purple-600 hover:from-blue-600 hover:to-purple-700 disabled:from-slate-700 disabled:to-slate-700 disabled:cursor-not-allowed text-white font-semibold rounded-lg transition-all duration-200"
          >
            {loading ? 'Logging in...' : 'Login'}
          </button>
        </form>

        <div className="mt-4 text-xs text-slate-400">
          Password is <span className="text-white font-semibold">123</span>. Wrong details will fail login.
        </div>
      </div>

      {error && <div className="bg-red-900 border border-red-700 text-red-200 px-4 py-3 rounded-lg">{error}</div>}

      {loading ? (
        <div className="flex justify-center items-center py-12">
          <div className="relative">
            <div className="w-12 h-12 border-4 border-slate-700 rounded-full"></div>
            <div
              className="absolute top-0 left-0 w-12 h-12 border-4 border-blue-500 rounded-full animate-spin"
              style={{ borderTopColor: 'transparent', borderRightColor: 'transparent' }}
            ></div>
          </div>
        </div>
      ) : (
        <div className="space-y-4">
          {!loggedIn ? (
            <div className="bg-slate-800 border border-slate-700 rounded-lg p-8 text-center">
              <p className="text-slate-400 text-lg">Please login to view and confirm bookings.</p>
            </div>
          ) : pendingBookings.length === 0 ? (
            <div className="bg-slate-800 border border-slate-700 rounded-lg p-8 text-center">
              <p className="text-slate-400 text-lg">No pending bookings found for your expert.</p>
            </div>
          ) : (
            <div className="grid grid-cols-1 gap-4">
              {pendingBookings.map((booking) => (
                <div
                  key={booking._id}
                  className="bg-slate-800 border border-slate-700 rounded-lg p-6 hover:border-blue-500/50 transition-colors duration-200"
                >
                  <div className="flex flex-col md:flex-row justify-between gap-6">
                    <div className="flex-1 space-y-3">
                      <div>
                        <h3 className="text-2xl font-bold text-white">{booking.clientName || 'Client'}</h3>
                        <p className="text-blue-400 text-sm">{booking.clientEmail}</p>
                      </div>

                      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 py-3 border-y border-slate-700">
                        <div>
                          <p className="text-slate-400 text-sm">Date</p>
                          <p className="text-white font-semibold">
                            {new Date(booking.timeSlotId?.date).toLocaleDateString('en-US', {
                              month: 'short',
                              day: 'numeric',
                              year: 'numeric',
                            })}
                          </p>
                        </div>
                        <div>
                          <p className="text-slate-400 text-sm">Time</p>
                          <p className="text-white font-semibold">
                            {booking.timeSlotId?.startTime} - {booking.timeSlotId?.endTime}
                          </p>
                        </div>
                        <div>
                          <p className="text-slate-400 text-sm">Status</p>
                          <span className="inline-block px-3 py-1 rounded-full text-xs font-bold bg-yellow-900 text-yellow-200">
                            Pending
                          </span>
                        </div>
                        <div>
                          <p className="text-slate-400 text-sm">Rate</p>
                          <p className="text-green-400 font-semibold">${booking.expertId?.hourlyRate}/hour</p>
                        </div>
                      </div>

                      {booking.notes && (
                        <div className="bg-slate-900 rounded p-3 border border-slate-700">
                          <p className="text-slate-400 text-sm">Client Notes</p>
                          <p className="text-slate-300">{booking.notes}</p>
                        </div>
                      )}
                    </div>

                    <div className="w-full md:w-auto flex items-start">
                      <button
                        onClick={() => handleConfirm(booking._id)}
                        disabled={confirmingId === booking._id}
                        className="w-full md:w-auto px-6 py-2 bg-gradient-to-r from-blue-500 to-purple-600 hover:from-blue-600 hover:to-purple-700 disabled:from-slate-700 disabled:to-slate-700 disabled:cursor-not-allowed text-white font-semibold rounded-lg transition-all duration-200 h-fit whitespace-nowrap shadow-lg shadow-blue-500/10"
                      >
                        {confirmingId === booking._id ? 'Confirming...' : 'Confirm Booking'}
                      </button>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      )}
    </div>
  );
};

export default ExpertBookings;
